import{_ as a,c as i,a1 as o,o as r}from"./chunks/framework.CWcXGLD-.js";const t="/hinata-docs-vitepress/assets/hcp0.D2hTyfDd.png",l="/hinata-docs-vitepress/assets/hcp1.GEBrWMjn.png",I=JSON.parse('{"title":"HINATA 控制中心","description":"","frontmatter":{},"headers":[],"relativePath":"HCP/index.md","filePath":"HCP/index.md"}'),s={name:"HCP/index.md"};function c(d,e,n,p,m,h){return r(),i("div",null,e[0]||(e[0]=[o('<h1 id="hinata-控制中心" tabindex="-1">HINATA 控制中心 <a class="header-anchor" href="#hinata-控制中心" aria-label="Permalink to &quot;HINATA 控制中心&quot;">​</a></h1><p><strong>该功能仅限标准版</strong></p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>HINATA控制中心用于控制HINATA的各项设置以及写卡用，调整的设置不会存储在HINATA内，HINATA断电不会保存设置。但是控制中心会保存设置，HINATA重连回控制中心后会自动同步回上次设置。</p><p>以后会重构控制中心以及让读卡器可以持久化设置。</p><p><a href="https://github.com/nerimoe/HINATA-release/releases/download/HINATA-2024090300/HINATA-Control-Panel-2024050400.7z" target="_blank" rel="noreferrer">点我下载HINATA控制中心，中国大陆用户如果下载比较慢的话可以在售后群群文件下载</a></p><p><img src="'+t+'" alt="hcp0"></p><h2 id="主页开关" tabindex="-1">主页开关 <a class="header-anchor" href="#主页开关" aria-label="Permalink to &quot;主页开关&quot;">​</a></h2><ol><li>PN532直通模式，可以将串口直通为PN532设备，在第三方的NFC工具中使用 （默认关闭）</li><li>深色主题与亮色主题切换，在右上角</li><li>底部的滑块用于调整SEGA串口模式时的亮度(AimeIO方式下亮度可以在<code>segatools.ini</code>内调整)，旁边的按钮进入设置闲置时灯光的页面</li><li><strong>控制中心内暂未实现固件更新，目前那个按钮没啥用，请使用该文档内的方法更新</strong></li></ol><h2 id="卡片读写" tabindex="-1">卡片读写 <a class="header-anchor" href="#卡片读写" aria-label="Permalink to &quot;卡片读写&quot;">​</a></h2><p><img src="'+l+'" alt="hcp1"></p><ul><li>该页面用于读取卡片信息和把<a href="https://s.taobao.com/search?commend=all&amp;ie=utf8&amp;initiative_id=tbindexz_20170306&amp;page=1&amp;q=m1%E7%99%BD%E5%8D%A1&amp;search_type=item&amp;sourceId=tb.index" target="_blank" rel="noreferrer">兼容的卡片</a>写入为Aime卡</li><li>当放置了<a href="https://s.taobao.com/search?commend=all&amp;ie=utf8&amp;initiative_id=tbindexz_20170306&amp;page=1&amp;q=m1%E7%99%BD%E5%8D%A1&amp;search_type=item&amp;sourceId=tb.index" target="_blank" rel="noreferrer">兼容的卡片</a>(Mifare Classic 1k)并且该卡可写入时可以自动弹出写入框和写入按钮，可以写入20位<code>Access Code</code>用于SEGA游戏或开启了<code>Access Code</code>读取功能的CardIO</li><li>赠送的白色卡片也从这里写卡</li><li>请不要在游戏中开启卡片读写页面，否则会导致与游戏通讯出现问题</li></ul><h2 id="cardio设置" tabindex="-1">CardIO设置 <a class="header-anchor" href="#cardio设置" aria-label="Permalink to &quot;CardIO设置&quot;">​</a></h2><ol><li>CardIO是用于 KONAMI游戏 以及 太鼓达人 的，如果只玩SEGA游戏的话下面可以忽略</li><li>UID开关：开启/关闭 对于M1卡UID读取的支持 （默认开启）</li><li>Access Code开关： 开启/关闭 对于旧版 Aime 卡或旧版 Aime 兼容卡的20位卡号读取的支持 （默认关闭）</li></ol><h3 id="cardio额外说明" tabindex="-1">CardIO额外说明 <a class="header-anchor" href="#cardio额外说明" aria-label="Permalink to &quot;CardIO额外说明&quot;">​</a></h3><p>CardIO兼容的游戏(konami游戏和太鼓达人)接收一个8字节的16进制数据，并且第一个字符必须为0</p><p>一张普通的 <code>Mifare Classic 1K</code>（M1）卡的UID有4个字节；</p><ul><li><p>开启UID读取后，读取M1卡时会将CardIO数据的前四字节填入M1卡的UID，并且第一位会被修改为0，后面四字节全部填0</p><p>例如：卡片的UID为 <code>11:45:14:19</code> 那么发送进游戏的数据将是 <code>01:45:14:19:00:00:00:00</code></p></li><li><p>Access Code开关在开启后，读取到 旧版<strong>Aime</strong> 时，会将20位的 Access Code转换为 8字节的16进制数据。 例如：一张卡片的卡号是<code>11451419198101145141</code> ，当刷卡后，读卡器将会把它转换为 <code>0e:eb:9d:16:a4:e8:46:35</code> 后发给游戏</p></li><li><p>由于 旧版 Aime 卡 是M1卡片，在有<code>Access Code</code>卡号的同时也有 UID 所以</p><ul><li>当关闭Access Code开关，但开启UID开关时，会把卡片当作 普通M1卡处理，将UID发送给游戏</li><li>当开启Access Code开关，但关闭UID开关时，将只会接受 旧版 Aime 卡 ，而不会接受普通的，非 Aime 的M1卡片，并将Access Code转换为16进制发送给游戏</li><li>当两个开关同时开启时，刷卡时如果刷到 旧版 Aime 卡 时，会将Access Code发送给游戏，如果发现卡片并非 Aime 卡，而是普通M1卡片，则会将UID发送给游戏</li><li>当两个开关都关闭时，将不接受任何 旧版 Aime 卡 和 普通M1卡片 ，只接受 Felica 卡片</li></ul></li><li><p><strong>Felica</strong> 卡片( <strong>Amusement IC</strong> ，<strong>Suica</strong> 等 )在任何时候都可以刷，不受这两个开关控制</p></li><li><p>氧无面板在绑定卡号时会过滤卡号，卡号非01:2e开头的通常会被拒绝绑定</p></li></ul>',18)]))}const u=a(s,[["render",c]]);export{I as __pageData,u as default};
